// // This D flip-flop captures the value of the D input on the falling edge of the clock and resets to 1 when the reset signal is deasserted.
module d_flip_flop (
    input wire clk,
    input wire rst,
    input wire d,
    output reg q
    );

always @(posedge clk or posedge rst) begin
    if (rst)
        q <= 1'b0;
    else
        q <= d;
end

endmodule
